import{_ as e,o as r,c as a,ag as i}from"./chunks/framework.6MCaaFDc.js";const u=JSON.parse('{"title":"Cybercrime","description":"","frontmatter":{},"headers":[],"relativePath":"theory/social/cybercrime.md","filePath":"theory/social/cybercrime.md"}'),s={name:"theory/social/cybercrime.md"};function o(n,t,d,l,c,h){return r(),a("div",null,[...t[0]||(t[0]=[i('<h1 id="cybercrime" tabindex="-1">Cybercrime <a class="header-anchor" href="#cybercrime" aria-label="Permalink to &quot;Cybercrime&quot;">​</a></h1><p>As more of our lives move online — banking, shopping, communication, health records — the potential for harm grows with it. Cybercrime costs the global economy trillions of rands annually. Understanding the threats, how they work, and how to protect against them is core Paper 2 content.</p><div class="note custom-block github-alert"><p class="custom-block-title">Grade 11+</p><p>Cybercrime types, prevention, and legislation are extended in Grade 11. Network security (encryption, SSL) is a Grade 12 focus.</p></div><hr><h2 id="what-is-cybercrime" tabindex="-1">What is Cybercrime? <a class="header-anchor" href="#what-is-cybercrime" aria-label="Permalink to &quot;What is Cybercrime?&quot;">​</a></h2><p><strong>Cybercrime</strong> is any criminal activity that involves a computer or network — either as the tool used to commit the crime, or as the target of the crime.</p><hr><h2 id="types-of-cybercrime" tabindex="-1">Types of Cybercrime <a class="header-anchor" href="#types-of-cybercrime" aria-label="Permalink to &quot;Types of Cybercrime&quot;">​</a></h2><h3 id="hacking" tabindex="-1">Hacking <a class="header-anchor" href="#hacking" aria-label="Permalink to &quot;Hacking&quot;">​</a></h3><p><strong>Hacking</strong> is gaining unauthorised access to a computer system or network.</p><table tabindex="0"><thead><tr><th>Type</th><th>Description</th></tr></thead><tbody><tr><td><strong>Black hat hacker</strong></td><td>Malicious intent — steal data, cause damage</td></tr><tr><td><strong>White hat hacker</strong></td><td>Ethical hacker — paid to find vulnerabilities (penetration testing)</td></tr><tr><td><strong>Grey hat hacker</strong></td><td>Breaks in without permission, but typically reports findings</td></tr></tbody></table><p><strong>Methods hackers use:</strong></p><ul><li>Exploiting software vulnerabilities (bugs/flaws in code)</li><li>Social engineering (tricking people into revealing credentials)</li><li>Brute force attacks (trying many passwords until one works)</li><li>Man-in-the-middle attacks (intercepting communications)</li></ul><hr><h3 id="malware" tabindex="-1">Malware <a class="header-anchor" href="#malware" aria-label="Permalink to &quot;Malware&quot;">​</a></h3><p><strong>Malware</strong> (malicious software) is any program designed to damage, disrupt, or gain unauthorised access to a system.</p><table tabindex="0"><thead><tr><th>Type</th><th>Behaviour</th><th>How it spreads</th></tr></thead><tbody><tr><td><strong>Virus</strong></td><td>Attaches to a legitimate file; activates when file is opened</td><td>File sharing, infected downloads</td></tr><tr><td><strong>Worm</strong></td><td>Self-replicates across networks without user action</td><td>Network vulnerabilities</td></tr><tr><td><strong>Trojan horse</strong></td><td>Disguised as legitimate software; opens a backdoor</td><td>Malicious downloads, fake software</td></tr><tr><td><strong>Ransomware</strong></td><td>Encrypts files; demands payment for decryption key</td><td>Phishing emails, infected sites</td></tr><tr><td><strong>Spyware</strong></td><td>Secretly monitors user activity, logs keystrokes</td><td>Bundled with free software</td></tr><tr><td><strong>Adware</strong></td><td>Displays unwanted advertisements</td><td>Bundled software, malicious websites</td></tr><tr><td><strong>Rootkit</strong></td><td>Hides deep in OS, giving persistent hidden access</td><td>Advanced malware</td></tr><tr><td><strong>Keylogger</strong></td><td>Records all keystrokes to capture passwords</td><td>Installed by Trojans or physical access</td></tr><tr><td><strong>Botnet</strong></td><td>Network of infected &quot;zombie&quot; computers controlled remotely</td><td>Worms, Trojans</td></tr></tbody></table><hr><h3 id="phishing" tabindex="-1">Phishing <a class="header-anchor" href="#phishing" aria-label="Permalink to &quot;Phishing&quot;">​</a></h3><p><strong>Phishing</strong> is a social engineering attack that tricks users into revealing sensitive information (passwords, credit card numbers, ID numbers) by pretending to be a trusted entity.</p><p><strong>How phishing works:</strong></p><ol><li>Victim receives an email appearing to be from their bank/Netflix/SARS</li><li>Email contains an urgent message and a link</li><li>Link leads to a fake website that looks identical to the real one</li><li>Victim enters their credentials — now the attacker has them</li></ol><p><strong>Variations:</strong></p><ul><li><strong>Spear phishing</strong>: Targeted phishing using personal information to seem credible</li><li><strong>Vishing</strong>: Voice phishing — phone calls pretending to be from banks/SARS</li><li><strong>Smishing</strong>: SMS phishing — fraudulent text messages</li><li><strong>Whaling</strong>: Phishing targeting senior executives/high-value targets</li></ul><hr><h3 id="identity-theft" tabindex="-1">Identity Theft <a class="header-anchor" href="#identity-theft" aria-label="Permalink to &quot;Identity Theft&quot;">​</a></h3><p><strong>Identity theft</strong> is obtaining and using someone else&#39;s personal information — ID number, banking details, passwords — to commit fraud or other crimes.</p><p><strong>How information is obtained:</strong></p><ul><li>Phishing attacks</li><li>Data breaches</li><li>Malware (keyloggers, spyware)</li><li>Shoulder surfing</li><li>Dumpster diving (finding discarded statements/documents)</li><li>Social media oversharing</li></ul><p><strong>Consequences for victims:</strong></p><ul><li>Fraudulent bank transactions</li><li>New accounts or loans opened in their name</li><li>Criminal records attached to their identity</li><li>Years to resolve and restore credit</li></ul><hr><h3 id="other-cybercrime-types" tabindex="-1">Other Cybercrime Types <a class="header-anchor" href="#other-cybercrime-types" aria-label="Permalink to &quot;Other Cybercrime Types&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Crime</th><th>Description</th></tr></thead><tbody><tr><td><strong>Cyberbullying</strong></td><td>Using technology to harass, threaten, or humiliate individuals</td></tr><tr><td><strong>Online fraud</strong></td><td>Fake online stores, lottery scams, advance fee fraud (419 scams)</td></tr><tr><td><strong>DDoS attack</strong></td><td>Distributed Denial of Service — flooding a server with requests to crash it</td></tr><tr><td><strong>SQL injection</strong></td><td>Inserting malicious SQL code into a web form to access/manipulate a database</td></tr><tr><td><strong>Spoofing</strong></td><td>Faking the sender identity of an email/message or IP address</td></tr><tr><td><strong>Piracy</strong></td><td>Distributing copyrighted software, music, film without authorisation</td></tr><tr><td><strong>Cyber espionage</strong></td><td>Stealing confidential government or corporate data</td></tr><tr><td><strong>Sexting / image-based abuse</strong></td><td>Distributing intimate images without consent</td></tr></tbody></table><hr><h2 id="protecting-against-cybercrime" tabindex="-1">Protecting Against Cybercrime <a class="header-anchor" href="#protecting-against-cybercrime" aria-label="Permalink to &quot;Protecting Against Cybercrime&quot;">​</a></h2><h3 id="technical-measures" tabindex="-1">Technical Measures <a class="header-anchor" href="#technical-measures" aria-label="Permalink to &quot;Technical Measures&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Measure</th><th>What it does</th></tr></thead><tbody><tr><td><strong>Antivirus / anti-malware</strong></td><td>Detects and removes malicious software</td></tr><tr><td><strong>Firewall</strong></td><td>Monitors and filters incoming/outgoing network traffic</td></tr><tr><td><strong>Software updates / patches</strong></td><td>Fixes known security vulnerabilities</td></tr><tr><td><strong>Encryption</strong></td><td>Scrambles data so only authorised parties can read it</td></tr><tr><td><strong>HTTPS / SSL</strong></td><td>Encrypts web traffic between browser and server</td></tr><tr><td><strong>Two-factor authentication (2FA)</strong></td><td>Requires second verification (OTP, app) beyond password</td></tr><tr><td><strong>Strong passwords</strong></td><td>Long, complex, unique — not reused across sites</td></tr><tr><td><strong>Password manager</strong></td><td>Generates and stores unique complex passwords</td></tr><tr><td><strong>VPN</strong></td><td>Encrypts all internet traffic; hides IP address</td></tr><tr><td><strong>Backup</strong></td><td>Regular copies of data so ransomware attacks can be recovered from</td></tr></tbody></table><h3 id="human-measures-education" tabindex="-1">Human Measures (Education) <a class="header-anchor" href="#human-measures-education" aria-label="Permalink to &quot;Human Measures (Education)&quot;">​</a></h3><table tabindex="0"><thead><tr><th>Practice</th><th>Why</th></tr></thead><tbody><tr><td>Never click suspicious links in emails</td><td>Prevents phishing</td></tr><tr><td>Verify the sender&#39;s actual email address</td><td>Spoofed display names look real</td></tr><tr><td>Never give passwords or OTPs over phone</td><td>Banks never ask for this</td></tr><tr><td>Use 2FA on important accounts</td><td>Even compromised passwords need a second factor</td></tr><tr><td>Keep software updated</td><td>Patches close exploited vulnerabilities</td></tr><tr><td>Be cautious of what you share on social media</td><td>Reduces spear phishing effectiveness</td></tr><tr><td>Use HTTPS sites for any sensitive transaction</td><td>Prevents man-in-the-middle interception</td></tr></tbody></table><hr><h2 id="south-african-legislation" tabindex="-1">South African Legislation <a class="header-anchor" href="#south-african-legislation" aria-label="Permalink to &quot;South African Legislation&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Act</th><th>Relevance</th></tr></thead><tbody><tr><td><strong>Electronic Communications and Transactions Act (ECT Act, 2002)</strong></td><td>Criminalises hacking, data interception, computer misuse</td></tr><tr><td><strong>Cybercrimes Act (19 of 2020)</strong></td><td>More comprehensive; covers ransomware, unlawful access, fake information</td></tr><tr><td><strong>POPIA (Protection of Personal Information Act, 2013)</strong></td><td>Organisations must protect personal data; failure = fines up to R10 million</td></tr></tbody></table><hr><h2 id="key-terms" tabindex="-1">Key Terms <a class="header-anchor" href="#key-terms" aria-label="Permalink to &quot;Key Terms&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Term</th><th>Definition</th></tr></thead><tbody><tr><td><strong>Cybercrime</strong></td><td>Criminal activity involving a computer or network</td></tr><tr><td><strong>Malware</strong></td><td>Software designed to damage, disrupt, or gain unauthorised access</td></tr><tr><td><strong>Virus</strong></td><td>Malware that attaches to files and spreads when shared</td></tr><tr><td><strong>Worm</strong></td><td>Self-replicating malware that spreads through networks</td></tr><tr><td><strong>Trojan horse</strong></td><td>Malware disguised as legitimate software</td></tr><tr><td><strong>Ransomware</strong></td><td>Malware that encrypts files and demands payment</td></tr><tr><td><strong>Phishing</strong></td><td>Deceptive messages tricking users into revealing credentials</td></tr><tr><td><strong>Spear phishing</strong></td><td>Targeted phishing using personal information</td></tr><tr><td><strong>Identity theft</strong></td><td>Using someone else&#39;s personal information for fraud</td></tr><tr><td><strong>DDoS</strong></td><td>Distributed Denial of Service — overwhelming a server with traffic</td></tr><tr><td><strong>SQL injection</strong></td><td>Inserting malicious SQL code through a web form</td></tr><tr><td><strong>Firewall</strong></td><td>Hardware/software filtering network traffic for security</td></tr><tr><td><strong>2FA</strong></td><td>Two-Factor Authentication — two forms of verification required</td></tr><tr><td><strong>VPN</strong></td><td>Virtual Private Network — encrypts and anonymises internet traffic</td></tr><tr><td><strong>POPIA</strong></td><td>South African law protecting personal information</td></tr></tbody></table><hr><h2 id="exam-focus" tabindex="-1">Exam Focus <a class="header-anchor" href="#exam-focus" aria-label="Permalink to &quot;Exam Focus&quot;">​</a></h2><div class="important custom-block github-alert"><p class="custom-block-title">High-Frequency Questions</p><p></p><ol><li><p><strong>&quot;Explain what phishing is and describe how to identify a phishing email&quot;</strong> — fake trusted sender, urgent message, suspicious link; identify by: hover over link (URL mismatch), sender email doesn&#39;t match organisation, grammar errors, unsolicited request</p></li><li><p><strong>&quot;Name and describe THREE types of malware&quot;</strong> — know virus, worm, Trojan, ransomware, spyware — always describe what each does specifically</p></li><li><p><strong>&quot;Give FOUR measures to protect a computer against cybercrime&quot;</strong> — can mix technical (antivirus, firewall, 2FA, updates) with human (strong passwords, don&#39;t click links)</p></li><li><p><strong>&quot;What is the difference between a virus and a worm?&quot;</strong> — virus: attaches to files, needs user action to spread; worm: self-replicates, spreads automatically through networks</p></li><li><p><strong>&quot;Why is two-factor authentication more secure than a password alone?&quot;</strong> — even if password is stolen/guessed, attacker still needs second factor (OTP, physical token) which they don&#39;t have</p></li></ol></div>',49)])])}const m=e(s,[["render",o]]);export{u as __pageData,m as default};
